"use strict";parserFactory.register("wenku8.net",()=>new Wenku8Parser);class Wenku8Parser extends Parser{constructor(){super()}getChapterUrls(e){let t=` https://www.wenku8.net/modules/article/reader.php?aid=${Wenku8Parser.extractBookId(e)}`;return HttpClient.wrapFetch(t,this.makeOptions()).then(function(e){let t=e.responseXML.querySelector("table");return Promise.resolve(util.hyperlinksToChapterList(t))})}static extractBookId(e){let t=new URL(e.baseURI).pathname.split("/");return t[t.length-1].split(".")[0]}findContent(e){return e.querySelector("#contentmain")}extractTitleImpl(e){return e.querySelector("tbody td b").textContent}extractLanguage(){return"zh"}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"ul#contentdp"),super.removeUnwantedElementsFromContentElement(e)}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div#content")}fetchChapter(e){return HttpClient.wrapFetch(e,this.makeOptions()).then(function(e){return Promise.resolve(e.responseXML)})}makeOptions(){return{makeTextDecoder:()=>new TextDecoder("GBK")}}}